import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface Feedback {
  id: string;
  sentiment: string;
  summary: string;
}

interface WidgetData {
  npsScore: number;
  npsTrend: number[];
  recentFeedback: Feedback[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const data: WidgetData = response.data;
  const meta: MetaData = response.meta;
  const clipPathId = useId();
  const isPositive = data.npsScore >= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Net Promoter Score
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: isPositive ? '#4CAF50' : '#F44336' }}>
              {data.npsScore}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isPositive ? <TrendingUp sx={{ fontSize: 16, color: '#4CAF50' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#F44336' }} />}
              <Typography variant="body2" sx={{ color: isPositive ? '#4CAF50' : '#F44336' }}>
                {isPositive ? 'Positive' : 'Negative'} Trend
              </Typography>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 120 }}>
            <LineChart
              height={120}
              series={[
                {
                  data: data.npsTrend,
                  color: meta.primaryColor,
                  curve: 'linear',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: data.npsTrend.map((_, i) => i), hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>

          <Typography variant="body2" sx={{ mb: 1 }}>
            Recent Feedback
          </Typography>
          <Stack direction="row" spacing={0.5}>
            {data.recentFeedback.map((feedback) => (
              <Chip
                key={feedback.id}
                label={feedback.summary}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: feedback.sentiment === 'positive' ? '#E8F5E9' : feedback.sentiment === 'neutral' ? '#FFFDE7' : '#FFEBEE', color: feedback.sentiment === 'positive' ? '#4CAF50' : feedback.sentiment === 'neutral' ? '#FBC02D' : '#F44336' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
